46: func newUnaryInterceptor(s *etcdserver.EtcdServer) grpc.UnaryServerInterceptor {
47: 	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
48: 		if !api.IsCapabilityEnabled(api.V3rpcCapability) {
49: 			return nil, rpctypes.ErrGRPCNotCapable
50: 		}
51: 
52: 		if s.IsMemberExist(s.MemberID()) && s.IsLearner() && !isRPCSupportedForLearner(req) {
53: 			return nil, rpctypes.ErrGRPCNotSupportedForLearner
54: 		}
55: 
56: 		md, ok := metadata.FromIncomingContext(ctx)
57: 		if ok {
58: 			ver, vs := "unknown", md.Get(rpctypes.MetadataClientAPIVersionKey)
59: 			if len(vs) > 0 {
60: 				ver = vs[0]
61: 			}
62: 			if !utf8.ValidString(ver) {
63: 				return nil, rpctypes.ErrGRPCInvalidClientAPIVersion
64: 			}
65: 			clientRequests.WithLabelValues("unary", ver).Inc()
66: 
67: 			if ks := md[rpctypes.MetadataRequireLeaderKey]; len(ks) > 0 && ks[0] == rpctypes.MetadataHasLeader {
68: 				if s.Leader() == types.ID(raft.None) {
69: 					return nil, rpctypes.ErrGRPCNoLeader
70: 				}
71: 			}
72: 		}
73: 
74: 		return handler(ctx, req)
75: 	}
76: }
