78: func newLogUnaryInterceptor(s *etcdserver.EtcdServer) grpc.UnaryServerInterceptor {
79: 	return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
80: 		startTime := time.Now()
81: 		resp, err := handler(ctx, req)
82: 		lg := s.Logger()
83: 		if lg != nil { // acquire stats if debug level is enabled or RequestInfo is expensive
84: 			defer logUnaryRequestStats(ctx, lg, s.Cfg.WarningUnaryRequestDuration, info, startTime, req, resp)
85: 		}
86: 		return resp, err
87: 	}
88: }
89: 
90: func logUnaryRequestStats(ctx context.Context, lg *zap.Logger, warnLatency time.Duration, info *grpc.UnaryServerInfo, startTime time.Time, req any, resp any) {
91: 	duration := time.Since(startTime)
92: 	var enabledDebugLevel, expensiveRequest bool
93: 	if lg.Core().Enabled(zap.DebugLevel) {
94: 		enabledDebugLevel = true
95: 	}
96: 	if duration > warnLatency {
97: 		expensiveRequest = true
98: 	}
99: 	if !enabledDebugLevel && !expensiveRequest {
100: 		return
101: 	}
102: 	remote := "No remote client info."
103: 	peerInfo, ok := peer.FromContext(ctx)
104: 	if ok {
105: 		remote = peerInfo.Addr.String()
106: 	}
107: 	responseType := info.FullMethod
108: 	var reqCount, respCount int64
109: 	var reqSize, respSize int
110: 	var reqContent string
111: 	switch _resp := resp.(type) {
112: 	case *pb.RangeResponse:
113: 		_req, ok := req.(*pb.RangeRequest)
114: 		if ok {
115: 			reqCount = 0
116: 			reqSize = _req.Size()
117: 			reqContent = _req.String()
118: 		}
119: 		if _resp != nil {
120: 			respCount = _resp.GetCount()
121: 			respSize = _resp.Size()
122: 		}
123: 	case *pb.PutResponse:
124: 		_req, ok := req.(*pb.PutRequest)
125: 		if ok {
126: 			reqCount = 1
127: 			reqSize = _req.Size()
128: 			reqContent = pb.NewLoggablePutRequest(_req).String()
129: 			// redact value field from request content, see PR #9821
130: 		}
131: 		if _resp != nil {
132: 			respCount = 0
133: 			respSize = _resp.Size()
134: 		}
135: 	case *pb.DeleteRangeResponse:
136: 		_req, ok := req.(*pb.DeleteRangeRequest)
137: 		if ok {
138: 			reqCount = 0
139: 			reqSize = _req.Size()
140: 			reqContent = _req.String()
141: 		}
142: 		if _resp != nil {
143: 			respCount = _resp.GetDeleted()
144: 			respSize = _resp.Size()
145: 		}
146: 	case *pb.TxnResponse:
147: 		_req, ok := req.(*pb.TxnRequest)
148: 		if ok && _resp != nil {
149: 			if _resp.GetSucceeded() { // determine the 'actual' count and size of request based on success or failure
150: 				reqCount = int64(len(_req.GetSuccess()))
151: 				reqSize = 0
152: 				for _, r := range _req.GetSuccess() {
153: 					reqSize += r.Size()
154: 				}
155: 			} else {
156: 				reqCount = int64(len(_req.GetFailure()))
157: 				reqSize = 0
158: 				for _, r := range _req.GetFailure() {
159: 					reqSize += r.Size()
160: 				}
161: 			}
162: 			reqContent = pb.NewLoggableTxnRequest(_req).String()
163: 			// redact value field from request content, see PR #9821
164: 		}
165: 		if _resp != nil {
166: 			respCount = 0
167: 			respSize = _resp.Size()
168: 		}
169: 	default:
170: 		reqCount = -1
171: 		reqSize = -1
172: 		respCount = -1
173: 		respSize = -1
174: 	}
175: 
176: 	if enabledDebugLevel {
177: 		logGenericRequestStats(lg, startTime, duration, remote, responseType, reqCount, reqSize, respCount, respSize, reqContent)
178: 	} else if expensiveRequest {
179: 		logExpensiveRequestStats(lg, startTime, duration, remote, responseType, reqCount, reqSize, respCount, respSize, reqContent)
180: 	}
181: }
182: 
183: func logGenericRequestStats(lg *zap.Logger, startTime time.Time, duration time.Duration, remote string, responseType string,
184: 	reqCount int64, reqSize int, respCount int64, respSize int, reqContent string,
185: ) {
186: 	lg.Debug("request stats",
187: 		zap.Time("start time", startTime),
188: 		zap.Duration("time spent", duration),
189: 		zap.String("remote", remote),
190: 		zap.String("response type", responseType),
191: 		zap.Int64("request count", reqCount),
192: 		zap.Int("request size", reqSize),
193: 		zap.Int64("response count", respCount),
194: 		zap.Int("response size", respSize),
195: 		zap.String("request content", reqContent),
196: 	)
197: }
198: 
199: func logExpensiveRequestStats(lg *zap.Logger, startTime time.Time, duration time.Duration, remote string, responseType string,
200: 	reqCount int64, reqSize int, respCount int64, respSize int, reqContent string,
201: ) {
202: 	lg.Warn("request stats",
203: 		zap.Time("start time", startTime),
204: 		zap.Duration("time spent", duration),
205: 		zap.String("remote", remote),
206: 		zap.String("response type", responseType),
207: 		zap.Int64("request count", reqCount),
208: 		zap.Int("request size", reqSize),
209: 		zap.Int64("response count", respCount),
210: 		zap.Int("response size", respSize),
211: 		zap.String("request content", reqContent),
212: 	)
213: }
