215: func newStreamInterceptor(s *etcdserver.EtcdServer) grpc.StreamServerInterceptor {
216: 	smap := monitorLeader(s)
217: 
218: 	return func(srv any, ss grpc.ServerStream, info *grpc.StreamServerInfo, handler grpc.StreamHandler) error {
219: 		if !api.IsCapabilityEnabled(api.V3rpcCapability) {
220: 			return rpctypes.ErrGRPCNotCapable
221: 		}
222: 
223: 		if s.IsMemberExist(s.MemberID()) && s.IsLearner() && info.FullMethod != snapshotMethod { // learner does not support stream RPC except Snapshot
224: 			return rpctypes.ErrGRPCNotSupportedForLearner
225: 		}
226: 
227: 		md, ok := metadata.FromIncomingContext(ss.Context())
228: 		if ok {
229: 			ver, vs := "unknown", md.Get(rpctypes.MetadataClientAPIVersionKey)
230: 			if len(vs) > 0 {
231: 				ver = vs[0]
232: 			}
233: 			if !utf8.ValidString(ver) {
234: 				return rpctypes.ErrGRPCInvalidClientAPIVersion
235: 			}
236: 			clientRequests.WithLabelValues("stream", ver).Inc()
237: 
238: 			if ks := md[rpctypes.MetadataRequireLeaderKey]; len(ks) > 0 && ks[0] == rpctypes.MetadataHasLeader {
239: 				if s.Leader() == types.ID(raft.None) {
240: 					return rpctypes.ErrGRPCNoLeader
241: 				}
242: 
243: 				ctx := newCancellableContext(ss.Context())
244: 				ss = serverStreamWithCtx{ctx: ctx, ServerStream: ss}
245: 
246: 				smap.mu.Lock()
247: 				smap.streams[ss] = struct{}{}
248: 				smap.mu.Unlock()
249: 
250: 				defer func() {
251: 					smap.mu.Lock()
252: 					delete(smap.streams, ss)
253: 					smap.mu.Unlock()
254: 					// TODO: investigate whether the reason for cancellation here is useful to know
255: 					ctx.Cancel(nil)
256: 				}()
257: 			}
258: 		}
259: 
260: 		return handler(srv, ss)
261: 	}
262: }
263: 
264: // cancellableContext wraps a context with new cancellable context that allows a
265: // specific cancellation error to be preserved and later retrieved using the
266: // Context.Err() function. This is so downstream context users can disambiguate
267: // the reason for the cancellation which could be from the client (for example)
268: // or from this interceptor code.
269: type cancellableContext struct {
270: 	context.Context
271: 
272: 	lock         sync.RWMutex
273: 	cancel       context.CancelFunc
274: 	cancelReason error
275: }
276: 
277: func newCancellableContext(parent context.Context) *cancellableContext {
278: 	ctx, cancel := context.WithCancel(parent)
279: 	return &cancellableContext{
280: 		Context: ctx,
281: 		cancel:  cancel,
282: 	}
283: }
284: 
285: // Cancel stores the cancellation reason and then delegates to context.WithCancel
286: // against the parent context.
287: func (c *cancellableContext) Cancel(reason error) {
288: 	c.lock.Lock()
289: 	c.cancelReason = reason
290: 	c.lock.Unlock()
291: 	c.cancel()
292: }
293: 
294: // Err will return the preserved cancel reason error if present, and will
295: // otherwise return the underlying error from the parent context.
296: func (c *cancellableContext) Err() error {
297: 	c.lock.RLock()
298: 	defer c.lock.RUnlock()
299: 	if c.cancelReason != nil {
300: 		return c.cancelReason
301: 	}
302: 	return c.Context.Err()
303: }
304: 
305: type serverStreamWithCtx struct {
306: 	grpc.ServerStream
307: 
308: 	// ctx is used so that we can preserve a reason for cancellation.
309: 	ctx *cancellableContext
310: }
311: 
312: func (ssc serverStreamWithCtx) Context() context.Context { return ssc.ctx }
313: 
314: func monitorLeader(s *etcdserver.EtcdServer) *streamsMap {
315: 	smap := &streamsMap{
316: 		streams: make(map[grpc.ServerStream]struct{}),
317: 	}
318: 
319: 	s.GoAttach(func() {
320: 		election := time.Duration(s.Cfg.TickMs) * time.Duration(s.Cfg.ElectionTicks) * time.Millisecond
321: 		noLeaderCnt := 0
322: 
