218: 	return func(srv any, ss grpc.ServerStream, info *grpc.StreamServerInfo, handler grpc.StreamHandler) error {
219: 		if !api.IsCapabilityEnabled(api.V3rpcCapability) {
220: 			return rpctypes.ErrGRPCNotCapable
221: 		}
222: 
223: 		if s.IsMemberExist(s.MemberID()) && s.IsLearner() && info.FullMethod != snapshotMethod { // learner does not support stream RPC except Snapshot
224: 			return rpctypes.ErrGRPCNotSupportedForLearner
225: 		}
226: 
227: 		md, ok := metadata.FromIncomingContext(ss.Context())
228: 		if ok {
229: 			ver, vs := "unknown", md.Get(rpctypes.MetadataClientAPIVersionKey)
230: 			if len(vs) > 0 {
231: 				ver = vs[0]
232: 			}
233: 			if !utf8.ValidString(ver) {
234: 				return rpctypes.ErrGRPCInvalidClientAPIVersion
235: 			}
236: 			clientRequests.WithLabelValues("stream", ver).Inc()
237: 
238: 			if ks := md[rpctypes.MetadataRequireLeaderKey]; len(ks) > 0 && ks[0] == rpctypes.MetadataHasLeader {
239: 				if s.Leader() == types.ID(raft.None) {
240: 					return rpctypes.ErrGRPCNoLeader
241: 				}
242: 
243: 				ctx := newCancellableContext(ss.Context())
244: 				ss = serverStreamWithCtx{ctx: ctx, ServerStream: ss}
245: 
246: 				smap.mu.Lock()
247: 				smap.streams[ss] = struct{}{}
248: 				smap.mu.Unlock()
249: 
250: 				defer func() {
251: 					smap.mu.Lock()
252: 					delete(smap.streams, ss)
253: 					smap.mu.Unlock()
254: 					// TODO: investigate whether the reason for cancellation here is useful to know
255: 					ctx.Cancel(nil)
256: 				}()
257: 			}
258: 		}
259: 
260: 		return handler(srv, ss)
261: 	}
262: }
