264: // cancellableContext wraps a context with new cancellable context that allows a
265: // specific cancellation error to be preserved and later retrieved using the
266: // Context.Err() function. This is so downstream context users can disambiguate
267: // the reason for the cancellation which could be from the client (for example)
268: // or from this interceptor code.
269: type cancellableContext struct {
270: 	context.Context
271: 
272: 	lock         sync.RWMutex
273: 	cancel       context.CancelFunc
274: 	cancelReason error
275: }
276: 
277: func newCancellableContext(parent context.Context) *cancellableContext {
278: 	ctx, cancel := context.WithCancel(parent)
279: 	return &cancellableContext{
280: 		Context: ctx,
281: 		cancel:  cancel,
282: 	}
283: }
284: 
285: // Cancel stores the cancellation reason and then delegates to context.WithCancel
286: // against the parent context.
287: func (c *cancellableContext) Cancel(reason error) {
288: 	c.lock.Lock()
289: 	c.cancelReason = reason
290: 	c.lock.Unlock()
291: 	c.cancel()
292: }
293: 
294: // Err will return the preserved cancel reason error if present, and will
295: // otherwise return the underlying error from the parent context.
296: func (c *cancellableContext) Err() error {
297: 	c.lock.RLock()
298: 	defer c.lock.RUnlock()
299: 	if c.cancelReason != nil {
300: 		return c.cancelReason
301: 	}
302: 	return c.Context.Err()
303: }
304: 
305: type serverStreamWithCtx struct {
306: 	grpc.ServerStream
307: 
308: 	// ctx is used so that we can preserve a reason for cancellation.
309: 	ctx *cancellableContext
310: }
311: 
312: func (ssc serverStreamWithCtx) Context() context.Context { return ssc.ctx }
313: 
314: func monitorLeader(s *etcdserver.EtcdServer) *streamsMap {
315: 	smap := &streamsMap{
316: 		streams: make(map[grpc.ServerStream]struct{}),
317: 	}
318: 
319: 	s.GoAttach(func() {
320: 		election := time.Duration(s.Cfg.TickMs) * time.Duration(s.Cfg.ElectionTicks) * time.Millisecond
321: 		noLeaderCnt := 0
322: 
323: 		for {
324: 			select {
325: 			case <-s.StoppingNotify():
326: 				return
327: 			case <-time.After(election):
328: 				if s.Leader() == types.ID(raft.None) {
329: 					noLeaderCnt++
330: 				} else {
331: 					noLeaderCnt = 0
332: 				}
333: 
334: 				// We are more conservative on canceling existing streams. Reconnecting streams
335: 				// cost much more than just rejecting new requests. So we wait until the member
336: 				// cannot find a leader for maxNoLeaderCnt election timeouts to cancel existing streams.
337: 				if noLeaderCnt >= maxNoLeaderCnt {
338: 					smap.mu.Lock()
339: 					for ss := range smap.streams {
340: 						if ssWithCtx, ok := ss.(serverStreamWithCtx); ok {
341: 							ssWithCtx.ctx.Cancel(rpctypes.ErrGRPCNoLeader)
342: 							<-ss.Context().Done()
343: 						}
344: 					}
345: 					smap.streams = make(map[grpc.ServerStream]struct{})
346: 					smap.mu.Unlock()
347: 				}
348: 			}
349: 		}
350: 	})
351: 
352: 	return smap
353: }
