{
  "source_files": [
    {
      "path": "metadata/metadata.go",
      "repo": "github.com/sg-evals/grpc-go--v1.4.0",
      "note": "Old API: FromContext (deprecated wrapper for FromIncomingContext) and NewContext (deprecated wrapper for NewOutgoingContext) still present"
    },
    {
      "path": "metadata/metadata.go",
      "repo": "github.com/sg-evals/grpc-go--3be7e2d0",
      "note": "New API only: FromContext and NewContext fully removed; only FromIncomingContext, FromOutgoingContext, NewIncomingContext, NewOutgoingContext remain"
    }
  ],
  "breaking_api_changes": {
    "removed": [
      {
        "function": "metadata.FromContext",
        "signature": "func FromContext(ctx context.Context) (MD, bool)",
        "behavior": "Was a wrapper for FromIncomingContext; reads mdIncomingKey from context",
        "replacement": "metadata.FromIncomingContext (server-side) or metadata.FromOutgoingContext (client-side)"
      },
      {
        "function": "metadata.NewContext",
        "signature": "func NewContext(ctx context.Context, md MD) context.Context",
        "behavior": "Was a wrapper for NewOutgoingContext; writes mdOutgoingKey to context",
        "replacement": "metadata.NewOutgoingContext (client-side) or metadata.NewIncomingContext (server-side)"
      }
    ],
    "added": [
      "metadata.NewIncomingContext — attach MD to server context (mdIncomingKey)",
      "metadata.NewOutgoingContext — attach MD to client context (mdOutgoingKey)",
      "metadata.FromIncomingContext — read server-side incoming MD (mdIncomingKey)",
      "metadata.FromOutgoingContext — read client-side outgoing MD (mdOutgoingKey)"
    ],
    "key_semantic_change": "mdIncomingKey and mdOutgoingKey are distinct unexported struct types. Code that sets metadata with NewOutgoingContext cannot read it with FromIncomingContext, and vice versa."
  },
  "affected_etcd_files": [
    {
      "path": "server/proxy/grpcproxy/watch.go",
      "line": 109,
      "breakage_type": "runtime_behavior_change",
      "severity": "critical",
      "description": "metadata.FromOutgoingContext(stream.Context()) used inside a gRPC server handler. Server contexts carry client metadata as INCOMING (mdIncomingKey), not outgoing. This call always returns ok=false, silently disabling MetadataRequireLeaderKey enforcement for all proxied Watch streams.",
      "correct_call": "metadata.FromIncomingContext(stream.Context())"
    },
    {
      "path": "server/proxy/grpcproxy/lease.go",
      "line": 158,
      "breakage_type": "runtime_behavior_change",
      "severity": "critical",
      "description": "metadata.FromOutgoingContext(stream.Context()) used inside LeaseKeepAlive server handler. Same bug as watch.go: MetadataRequireLeaderKey is never read, leader enforcement silently disabled for all proxied LeaseKeepAlive streams.",
      "correct_call": "metadata.FromIncomingContext(stream.Context())"
    },
    {
      "path": "server/etcdserver/api/v3rpc/interceptor.go",
      "line": 56,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Uses metadata.FromIncomingContext correctly in both unary and stream server interceptors."
    },
    {
      "path": "server/auth/store.go",
      "line": 1061,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Uses FromIncomingContext in AuthInfoFromCtx and AuthInfoFromTLS. Uses NewIncomingContext in WithRoot (intentionally bypassing gRPC transport for local calls)."
    },
    {
      "path": "server/proxy/grpcproxy/util.go",
      "line": 27,
      "breakage_type": "none",
      "severity": "ok",
      "description": "getAuthTokenFromClient uses FromIncomingContext correctly."
    },
    {
      "path": "server/etcdserver/api/etcdhttp/peer.go",
      "line": 146,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Uses NewIncomingContext to inject HTTP Authorization token into gRPC metadata context for PromoteMember."
    },
    {
      "path": "server/etcdserver/cluster_util.go",
      "line": 312,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Uses FromIncomingContext to extract auth token for forwarding to HTTP peer endpoint. Correct incoming→HTTP forwarding pattern."
    },
    {
      "path": "client/v3/ctx.go",
      "line": 29,
      "breakage_type": "none",
      "severity": "ok",
      "description": "WithRequireLeader and withVersion use FromOutgoingContext + NewOutgoingContext correctly on client side."
    },
    {
      "path": "client/v3/watch.go",
      "line": 1039,
      "breakage_type": "none",
      "severity": "ok",
      "description": "streamKeyFromCtx uses FromOutgoingContext correctly on client context."
    },
    {
      "path": "client/v3/lease.go",
      "line": 383,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Uses FromOutgoingContext correctly on client-side keep-alive contexts."
    },
    {
      "path": "client/v3/retry_interceptor.go",
      "line": 43,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Client unary interceptor; calls withVersion(ctx) which uses correct outgoing API."
    },
    {
      "path": "pkg/grpctesting/recorder.go",
      "line": 55,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Test helper server interceptor uses FromIncomingContext correctly."
    },
    {
      "path": "server/proxy/grpcproxy/adapter/chan_stream.go",
      "line": 1,
      "breakage_type": "none",
      "severity": "ok",
      "description": "Uses metadata.MD type only for stream header/trailer management; no context key reads or writes."
    }
  ],
  "compile_errors": [],
  "runtime_behavior_changes": [
    {
      "file": "server/proxy/grpcproxy/watch.go",
      "line": 109,
      "impact": "MetadataRequireLeaderKey check always skipped in Watch proxy handler. Clients using WithRequireLeader() will not get ErrNoLeader from the proxy even when the cluster has no leader.",
      "root_cause": "FromOutgoingContext used instead of FromIncomingContext on server-side stream context"
    },
    {
      "file": "server/proxy/grpcproxy/lease.go",
      "line": 158,
      "impact": "MetadataRequireLeaderKey check always skipped in LeaseKeepAlive proxy handler. Same consequence as watch.go.",
      "root_cause": "FromOutgoingContext used instead of FromIncomingContext on server-side stream context"
    }
  ],
  "critical_metadata_forwarding": {
    "description": "Two gRPC proxy server handlers (Watch and LeaseKeepAlive) use the wrong metadata accessor for their server-side stream contexts. This silently breaks the require-leader contract for clients routed through the proxy.",
    "affected_files": [
      "server/proxy/grpcproxy/watch.go:109",
      "server/proxy/grpcproxy/lease.go:158"
    ],
    "mechanism": "Client sets metadata via metadata.NewOutgoingContext (mdOutgoingKey). gRPC transport delivers it to the server as incoming metadata (mdIncomingKey). Proxy handlers call FromOutgoingContext instead of FromIncomingContext, so they read from the wrong key and always get ok=false.",
    "fix": "Replace metadata.FromOutgoingContext(stream.Context()) with metadata.FromIncomingContext(stream.Context()) in both proxy handlers."
  },
  "code_paths": [
    {
      "path": "server/proxy/grpcproxy/watch.go",
      "description": "Watch proxy server handler — critical metadata forwarding bug"
    },
    {
      "path": "server/proxy/grpcproxy/lease.go",
      "description": "LeaseKeepAlive proxy server handler — critical metadata forwarding bug"
    },
    {
      "path": "server/etcdserver/api/v3rpc/interceptor.go",
      "description": "Server-side unary + stream interceptors — correct API usage"
    },
    {
      "path": "server/auth/store.go",
      "description": "Auth store — correct API usage including NewIncomingContext for local RPC simulation"
    },
    {
      "path": "client/v3/ctx.go",
      "description": "Client metadata helpers — correct outgoing API usage"
    }
  ],
  "ownership": "grpc metadata context separation — affects server/proxy/grpcproxy (proxy leader enforcement) and is safe in server/auth, server/v3rpc, and all client-side code",
  "severity": {
    "level": "high",
    "rationale": "No compile errors since etcd already uses the new split API. However two proxy server handlers (watch.go:109 and lease.go:158) use FromOutgoingContext on server-side contexts, silently breaking MetadataRequireLeaderKey enforcement for any client connected through the gRPC proxy layer. This is a correctness bug with no visible error signal — affected clients believe they have leader-required semantics but the proxy ignores the metadata entirely."
  }
}

